def evict_tool_results(
    messages: list[dict],
    max_tokens: int,
    reserve: int = 4_000,
) -> list[dict]:
    """
    Drop verbose tool result bodies when the buffer is tight,
    replacing them with a compact placeholder.
    Preserves tool_use/tool_result pairing required by the API.
    """
    def compress(msg: dict) -> dict:
        if msg.get("role") == "tool" and isinstance(msg.get("content"), str):
            if len(msg["content"]) > 500:
                return {**msg, "content": "[tool result truncated — see earlier context]"}
        return msg

    compressed = [compress(m) for m in messages]
    if count_tokens(compressed) <= max_tokens - reserve:
        return compressed
    # Still over budget — fall back to sliding window
    return sliding_window(compressed, max_tokens, reserve)
